function icon(type: Category['icon']) { const p={size:22}; if(type==='user')return <User {...p}/>; if(type==='shield')return <ShieldCheck {...p}/>; if(type==='users')return <Users {...p}/>; return <Target {...p}/>; }
function infoIcon(name?:string){const p={size:22}; if(name==='calendar')return <CalendarDays {...p}/>; if(name==='clock')return <Clock {...p}/>; if(name==='shield')return <ShieldCheck {...p}/>; if(name==='target')return <Target {...p}/>; if(name==='info')return <Info {...p}/>; if(name==='map')return <MapPin {...p}/>; return <Home {...p}/>;}
function mapsHref(address?:string){return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address||'')}`}
function toMin(t:string){const [h,m]=t.split(':').map(Number);return h*60+m} function fromMin(n:number){return `${Math.floor(n/60).toString().padStart(2,'0')}:${(n%60).toString().padStart(2,'0')}`} function addMin(t:string,m:number){return fromMin(toMin(t)+m)} function overlaps(a:string,b:string,c:string,d:string){return toMin(a)<toMin(d)&&toMin(b)>toMin(c)}
function datePlus(days:number){const d=new Date();d.setDate(d.getDate()+days);return d.toISOString().slice(0,10)}
function dist(iso:string){return Math.round((new Date(`${iso}T00:00:00`).getTime()-new Date(`${datePlus(0)}T00:00:00`).getTime())/86400000)}
function isOpen(iso:string,s:Settings){return s.openDays.includes(new Date(`${iso}T12:00:00`).getDay())}
const localeByLang: Record<Lang,string> = { CZ:'cs-CZ', EN:'en-GB', DE:'de-DE', ES:'es-ES', FR:'fr-FR' };
const todayByLang: Record<Lang,string> = { CZ:'Dnes', EN:'Today', DE:'Heute', ES:'Hoy', FR:'Aujourd’hui' };
const tomorrowByLang: Record<Lang,string> = { CZ:'Zítra', EN:'Tomorrow', DE:'Morgen', ES:'Mañana', FR:'Demain' };
function formatDate(iso:string){return iso.split('-').reverse().join('.')}
function dayName(iso:string, lang:Lang='CZ'){return new Intl.DateTimeFormat(localeByLang[lang],{weekday:'long'}).format(new Date(`${iso}T12:00:00`))}
function emailOk(e:string){return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e)} function phoneOk(p:string){return /^\d{9,15}$/.test(p)}
function quickDates(settings:Settings, lang:Lang='CZ'){const f=new Intl.DateTimeFormat(localeByLang[lang],{weekday:'short',day:'numeric',month:'numeric'});return Array.from({length:7},(_,i)=>{const iso=datePlus(i);return {iso,label:i===0?todayByLang[lang]:i===1?tomorrowByLang[lang]:f.format(new Date(`${iso}T12:00:00`)),closed:!isOpen(iso,settings)}})}


