function normalizeTxt(text:string){return (text||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,' ').trim()}
const normalizedDynamicTextTranslations: Record<string, Partial<Record<Lang,string>>> = Object.fromEntries(Object.entries(dynamicTextTranslations).map(([k,v])=>[normalizeTxt(k),v]));
function fixMixedCzechAdminText(text:string){
  if(!text) return text;
  return text
    .replace(/Book a slot/gi,'Rezervovat termín')
    .replace(/Online booking/gi,'Online rezervace')
    .replace(/available term[ií]n/gi,'volný termín')
    .replace(/available/gi,'volný')
    .replace(/forti nevyužitým/gi,'proti nevyužitým')
    .replace(/forti/gi,'proti')
    .replace(/pravidla range/gi,'pravidla střelnice')
    .replace(/range/gi,'střelnice')
    .replace(/booking/gi,'rezervace')
    .replace(/fair rezervace/gi,'fér rezervace')
    .replace(/termín a potvrdte/gi,'termín a potvrďte')
    .replace(/potvrdte/gi,'potvrďte');
}
function autoTranslateCZ(text:string, lang:Lang){
  if(!text) return text;
  if(lang==='CZ') return fixMixedCzechAdminText(text);
  const clean = fixMixedCzechAdminText(text.trim());
  const exact = dynamicTextTranslations[clean]?.[lang] || normalizedDynamicTextTranslations[normalizeTxt(clean)]?.[lang];
  if(exact) return exact;
  let out = clean;
  // Silnější lokální slovník pro texty vytvořené adminem v češtině.
  // Nejdřív zkusí celé fráze, potom jednotlivá slova a běžné skloňované tvary.
  for (const [re, rep] of dynamicReplace[lang]) out = out.replace(re, rep);
  // Běžné tvary, které uživatel zadá v adminu jako název podslužby.
  const normalized = normalizeTxt(clean);
  const numericSuffix = clean.match(/\s+(\d+)$/)?.[1] || '';
  const phraseMap: Partial<Record<Lang, Record<string,string>>> = {
    EN: {'taktika strelby':'Shooting tactics','dynamicka strelba':'Dynamic shooting','staticka strelba':'Static shooting','zazitkova strelba':'Shooting experience','sportovni strelba':'Sport shooting','pronajem stavu':'Lane rental'},
    DE: {'taktika strelby':'Schießtaktik','dynamicka strelba':'Dynamisches Schießen','staticka strelba':'Statisches Schießen','zazitkova strelba':'Schießerlebnis','sportovni strelba':'Sportschießen','pronajem stavu':'Bahn-Miete'},
    ES: {'taktika strelby':'Táctica de tiro','dynamicka strelba':'Tiro dinámico','staticka strelba':'Tiro estático','zazitkova strelba':'Experiencia de tiro','sportovni strelba':'Tiro deportivo','pronajem stavu':'Alquiler de puesto'},
    FR: {'taktika strelby':'Tactique de tir','dynamicka strelba':'Tir dynamique','staticka strelba':'Tir statique','zazitkova strelba':'Expérience de tir','sportovni strelba':'Tir sportif','pronajem stavu':'Location de pas'},
  };
  const baseNormalized = normalized.replace(/\s+\d+$/,'');
  const mapped = phraseMap[lang]?.[baseNormalized];
  if(mapped) return numericSuffix ? `${mapped} ${numericSuffix}` : mapped;
  return out;
}
function tx(key:string, lang:Lang){return uiText[key]?.[lang]||uiText[key]?.CZ||key}
function trName(id:string, fallback:string, lang:Lang){return lang==='CZ'?fallback:(serviceTranslations[id]?.[lang]?.name||autoTranslateCZ(fallback,lang))}
function trDesc(id:string, fallback:string, lang:Lang){return lang==='CZ'?fallback:(serviceTranslations[id]?.[lang]?.description||autoTranslateCZ(fallback,lang))}
function isFuture(r:Reservation){return new Date(`${r.date}T${r.endTime}:00`).getTime() >= Date.now()}


function blockMatches(rule:any,date:string,serviceId:string,categoryId:string,start:string,end:string,settings:Settings){
  if(typeof rule==='string'){
    const parts=rule.includes('|')?rule.split('|'):['*',rule];
    const bd=parts[0], bt=parts[1];
    return (bd==='*'||bd===date)&&overlaps(start,end,bt,addMin(bt,settings.slotStep));
  }
  const bd=rule.date||'*';
  const bs=rule.start||rule.time;
  const be=rule.end||addMin(bs||'00:00',settings.slotStep);
  const scope:string[]=Array.isArray(rule.scope)?rule.scope:[];
  const scopeOk=!scope.length||scope.includes('all')||scope.includes(categoryId)||scope.includes(serviceId);
  return scopeOk&&(bd==='*'||bd===date)&&bs&&overlaps(start,end,bs,be);
}


function KarlinMark(){return <span className="karlin-mark" aria-label="Střelnice Karlín"><span/><i/><i/><i/></span>}
async function sendReservationEmail(reservation: Reservation, settings: Settings, checkUrl: string){
  try{
    await fetch('/api/email', {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({type:'reservation_confirmation', reservation, settings, checkUrl})});
  }catch(e){ console.warn('EMAIL_SEND_FAILED', e); }
}

